const resumeId = $('Code - Valida id e binário1').first().json.id;

const raw = $input.first().json.output
  || $input.first().json.message?.content
  || $input.first().json.choices?.[0]?.message?.content;

if (!raw) throw new Error('Resposta do AI Agent vazia. Raw: ' + JSON.stringify($input.first().json));

let parsed;
try {
  const clean = typeof raw === 'string' ? raw.replace(/```json|```/g, '').trim() : raw;
  parsed = typeof clean === 'string' ? JSON.parse(clean) : clean;
} catch(e) {
  throw new Error('JSON inválido retornado: ' + raw);
}

return [{
  json: {
    resume_id: resumeId,
    employability_score: parsed.employability_score,
    ats_rejection_chance: parsed.ats_rejection_chance,
    hook_message: parsed.hook_message,
    brutal_roast: parsed.brutal_roast,
    red_flags: JSON.stringify(parsed.red_flags),
    improvement_tips: JSON.stringify(parsed.improvement_tips),
    rewritten_summary: parsed.rewritten_summary,
    questions: JSON.stringify(parsed.questions || []),
    status: 'analyzed',
    created_at: new Date().toISOString()
  }
}];
